-- Import all 394 Salesforce Flows
-- This SQL will insert all flows with their metadata

-- First, get the organization_id (you'll need to replace this with your actual org ID)
-- For now, we'll use a placeholder that you can replace

DO $$
DECLARE
  v_org_id uuid;
  v_user_id uuid;
BEGIN
  -- Get the first organization (you can modify this to target specific org)
  SELECT id INTO v_org_id FROM organizations LIMIT 1;

  -- Get autoproc user or first admin user
  SELECT user_id INTO v_user_id
  FROM user_organization_roles
  WHERE organization_id = v_org_id
  AND role = 'admin'
  LIMIT 1;

